+namespace Microsoft.Integration.Shopify;
+
+using Microsoft.Sales.Document;
+
+/// <summary>
+/// Codeunit Shpfy Copy Document Subscribers (ID 30168).
+/// </summary>
+codeunit 30168 "Shpfy Copy Document Subscribers"
+{
+    Access = Internal;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnAfterCopySalesDocument', '', false, false)]
+    local procedure OnAfterCopySalesDocument(FromDocumentType: Option; FromDocumentNo: Code[20]; var ToSalesHeader: Record "Sales Header"; FromDocOccurenceNo: Integer; FromDocVersionNo: Integer; IncludeHeader: Boolean; RecalculateLines: Boolean; MoveNegLines: Boolean)
+    begin
+        if ToSalesHeader."Document Type" <> ToSalesHeader."Document Type"::Invoice then
+            exit;
+
+        if (ToSalesHeader."Shpfy Order Id" = 0) and (ToSalesHeader."Shpfy Order No." = '') then
+            exit;
+
+        ToSalesHeader."Shpfy Order Id" := 0;
+        ToSalesHeader."Shpfy Order No." := '';
+        ToSalesHeader.Modify(true);
+    end;
+}

